import type { FastifyInstance, FastifyRequest } from "fastify";
import { z } from "zod";
import type { AdminService } from "./admin.js";
import { AppError, forbidden } from "./errors.js";
import { isValidSshHost, isValidSshUsername } from "./ssh-validation.js";

const targetPayload = z.object({
  name: z.string().min(1).max(120),
  type: z.enum(["ssh", "cloudflare_tunnel"]),
  host: z.string().min(1).max(255).refine((value) => isValidSshHost(value), "Invalid SSH hostname or IP address."),
  port: z.coerce.number().int().min(1).max(65535).default(22),
  username: z.string().min(1).max(120).refine(isValidSshUsername, "Invalid SSH username."),
  auth_type: z.enum(["private_key", "password", "private_key_password", "agent"]).default("private_key"),
  secret_ref: z.string().max(500).nullable().optional(),
  tags: z.array(z.string().min(1).max(50)).max(20).default([]),
  working_directory: z.string().max(500).nullable().optional(),
  known_hosts: z.string().max(10_000).nullable().optional(),
  enabled: z.boolean().default(true),
});

const assignmentPayload = z.object({
  target_id: z.string().uuid(),
  command_id: z.string().uuid(),
});

function idParam(request: FastifyRequest, key: string): string {
  const value = (request.params as Record<string, string | undefined>)[key];
  if (!value) throw new AppError(400, "bad_request", `Missing ${key}.`);
  return value;
}

function requireAdmin(role: string): void {
  if (role !== "admin") throw forbidden("Only administrators can modify targets and command assignments.");
}

async function audit(admin: AdminService, actorId: string, action: string, entityType: string, entityId: string, metadata: Record<string, unknown> = {}): Promise<void> {
  await admin.rest("audit_logs", {
    method: "POST",
    body: { actor_id: actorId, action, entity_type: entityType, entity_id: entityId, metadata },
    prefer: "return=minimal",
  });
}

export function registerAdminUiRoutes(server: FastifyInstance, admin: AdminService): void {
  server.get("/admin/manage", async (_request, reply) => reply.type("text/html; charset=utf-8").send(managementHtml()));

  server.get("/admin/api/manage/targets", async (request) => {
    await admin.principal(request);
    return { targets: await admin.rest("targets", { query: "select=*&order=created_at.desc" }) };
  });

  server.post("/admin/api/manage/targets", async (request, reply) => {
    const principal = await admin.principal(request);
    requireAdmin(principal.role);
    const input = targetPayload.parse(request.body);
    const created = await admin.rest("targets", { method: "POST", body: { ...input, created_by: principal.id } });
    const row = Array.isArray(created) ? created[0] : undefined;
    if (row && typeof row === "object" && "id" in row) await audit(admin, principal.id, "target.created", "target", String(row.id), { name: input.name, type: input.type });
    return reply.code(201).send({ target: created });
  });

  server.patch("/admin/api/manage/targets/:id", async (request) => {
    const principal = await admin.principal(request);
    requireAdmin(principal.role);
    const id = idParam(request, "id");
    const input = targetPayload.partial().parse(request.body);
    const updated = await admin.rest("targets", { method: "PATCH", query: `id=eq.${encodeURIComponent(id)}`, body: input });
    await audit(admin, principal.id, "target.updated", "target", id, { fields: Object.keys(input) });
    return { target: updated };
  });

  server.delete("/admin/api/manage/targets/:id", async (request, reply) => {
    const principal = await admin.principal(request);
    requireAdmin(principal.role);
    const id = idParam(request, "id");
    await admin.rest("targets", { method: "DELETE", query: `id=eq.${encodeURIComponent(id)}`, prefer: "return=minimal" });
    await audit(admin, principal.id, "target.deleted", "target", id);
    return reply.code(204).send();
  });

  server.get("/admin/api/manage/target-commands", async (request) => {
    await admin.principal(request);
    const query = request.query as { target_id?: string };
    const filter = query.target_id ? `target_id=eq.${encodeURIComponent(z.string().uuid().parse(query.target_id))}&` : "";
    return { assignments: await admin.rest("target_commands", { query: `${filter}select=target_id,command_id` }) };
  });

  server.post("/admin/api/manage/target-commands", async (request, reply) => {
    const principal = await admin.principal(request);
    requireAdmin(principal.role);
    const input = assignmentPayload.parse(request.body);
    await admin.rest("target_commands", { method: "POST", body: input, prefer: "resolution=ignore-duplicates,return=minimal" });
    await audit(admin, principal.id, "target.command_assigned", "target", input.target_id, { command_id: input.command_id });
    return reply.code(201).send({ assignment: input });
  });

  server.delete("/admin/api/manage/target-commands/:targetId/:commandId", async (request, reply) => {
    const principal = await admin.principal(request);
    requireAdmin(principal.role);
    const targetId = z.string().uuid().parse(idParam(request, "targetId"));
    const commandId = z.string().uuid().parse(idParam(request, "commandId"));
    await admin.rest("target_commands", {
      method: "DELETE",
      query: `target_id=eq.${encodeURIComponent(targetId)}&command_id=eq.${encodeURIComponent(commandId)}`,
      prefer: "return=minimal",
    });
    await audit(admin, principal.id, "target.command_unassigned", "target", targetId, { command_id: commandId });
    return reply.code(204).send();
  });
}

